  1→/**
  2→ * Native IPC Handlers
  3→ *
  4→ * Registers ipcMain.handle() for native OS operations that the renderer
  5→ * accesses through the preload bridge.
  6→ *
  7→ * Handler names use the SAME names the renderer calls via invoke().
  8→ * The preload's generic invoke() forwards channel names unchanged, so
  9→ * snake_case names here must match the renderer exactly.
 10→ */
 11→
 12→import { ipcMain, dialog, nativeTheme, BrowserWindow, shell, Menu, app } from "electron";
 13→import { execFile } from "child_process";
 14→import { promisify } from "util";
 15→import { homedir } from "os";
 16→
 17→const execFileAsync = promisify(execFile);
 18→
 19→export function registerNativeHandlers(): void {
 20→  // -------------------------------------------------------------------------
 21→  // Window visibility
 22→  // -------------------------------------------------------------------------
 23→
 24→  ipcMain.handle("show_main_window", () => {
 25→    const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
 26→    if (win) {
 27→      win.show();
 28→      win.focus();
 29→    }
 30→  });
 31→
 32→  ipcMain.handle("enter_onboarding_mode", () => {
 33→    const win = BrowserWindow.getAllWindows()[0];
 34→    if (win) {
 35→      win.setBackgroundColor("#00000000");
 36→      win.show();
 37→    }
 38→  });
 39→
 40→  ipcMain.handle("exit_onboarding_mode", () => {
 41→    const win = BrowserWindow.getAllWindows()[0];
 42→    if (win) {
 43→      win.hide();
 44→    }
 45→  });
 46→
 47→  // -------------------------------------------------------------------------
 48→  // Folder picker
 49→  // -------------------------------------------------------------------------
 50→
 51→  ipcMain.handle("show_folder_dialog", async () => {
 52→    const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
 53→    if (!win) return null;
 54→    const result = await dialog.showOpenDialog(win, {
 55→      properties: ["openDirectory", "createDirectory"],
 56→    });
 57→    return result.canceled ? null : result.filePaths[0];
 58→  });
 59→
 60→  // Keep the native: prefixed name too — the preload's named methods
 61→  // (pickFolder, confirm, etc.) call "native:pickFolder" directly.
 62→  ipcMain.handle("native:pickFolder", async () => {
 63→    const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
 64→    if (!win) return null;
 65→    const result = await dialog.showOpenDialog(win, {
 66→      properties: ["openDirectory", "createDirectory"],
 67→    });
 68→    return result.canceled ? null : result.filePaths[0];
 69→  });
 70→
 71→  // -------------------------------------------------------------------------
 72→  // Confirm dialog
 73→  // -------------------------------------------------------------------------
 74→
 75→  ipcMain.handle(
 76→    "native:confirm",
 77→    async (_e, { message, detail }: { message: string; detail?: string }) => {
 78→      const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
 79→      if (!win) return false;
 80→      const { response } = await dialog.showMessageBox(win, {
 81→        type: "question",
 82→        buttons: ["Cancel", "Confirm"],
 83→        defaultId: 1,
 84→        message,
 85→        detail,
 86→      });
 87→      return response === 1;
 88→    }
 89→  );
 90→
 91→  // -------------------------------------------------------------------------
 92→  // Theme
 93→  // -------------------------------------------------------------------------
 94→
 95→  ipcMain.handle("native:setTheme", (_e, { theme }: { theme: "light" | "dark" | "system" }) => {
 96→    nativeTheme.themeSource = theme;
 97→  });
 98→
 99→  // -------------------------------------------------------------------------
100→  // Open external URL
101→  // -------------------------------------------------------------------------
102→
103→  ipcMain.handle("native:openExternal", (_e, { url }: { url: string }) => {
104→    // Security: only allow http/https URLs to prevent shell command injection
105→    // via custom protocol handlers (e.g., file://, javascript:, vbscript:).
106→    try {
107→      const parsed = new URL(url);
108→      if (parsed.protocol === "http:" || parsed.protocol === "https:") {
109→        shell.openExternal(url);
110→      }
111→    } catch {
112→      // Ignore malformed URLs
113→    }
114→  });
115→
116→  // -------------------------------------------------------------------------
117→  // Context menu
118→  // -------------------------------------------------------------------------
119→
120→  ipcMain.handle(
121→    "native:contextMenu",
122→    (
123→      _e,
124→      { items }: { items: Array<{ id: string; label: string; type?: string; enabled?: boolean }> }
125→    ) => {
126→      return new Promise<string | null>((resolve) => {
127→        const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
128→        if (!win) {
129→          resolve(null);
130→          return;
131→        }
132→        const menu = Menu.buildFromTemplate(
133→          items.map((item) => ({
134→            label: item.label,
135→            click: () => resolve(item.id),
136→            type: item.type as "normal" | "separator" | undefined,
137→            enabled: item.enabled ?? true,
138→          }))
139→        );
140→        menu.popup({ window: win, callback: () => resolve(null) });
141→      });
142→    }
143→  );
144→
145→  // -------------------------------------------------------------------------
146→  // Backend connection info (renderer needs this to connect WebSocket)
147→  // Registered under BOTH names:
148→  //   - "native:getBackendPort" — preload named method calls this directly
149→  //   - "get_backend_port"      — generic invoke() from renderer code
150→  // -------------------------------------------------------------------------
151→
152→  ipcMain.handle("native:getBackendPort", () => {
153→    return parseInt(process.env.OPENDEVS_BACKEND_PORT!, 10);
154→  });
155→
156→  ipcMain.handle("get_backend_port", () => {
157→    return parseInt(process.env.OPENDEVS_BACKEND_PORT!, 10);
158→  });
159→
160→  ipcMain.handle("native:getAuthToken", () => {
161→    return process.env.OPENDEVS_AUTH_TOKEN;
162→  });
163→
164→  // -------------------------------------------------------------------------
165→  // Window controls — keep native: prefix since preload methods call these
166→  // -------------------------------------------------------------------------
167→
168→  ipcMain.handle("native:minimize", () => {
169→    const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
170→    win?.minimize();
171→  });
172→
173→  ipcMain.handle("native:maximize", () => {
174→    const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
175→    if (win) {
176→      if (win.isMaximized()) {
177→        win.unmaximize();
178→      } else {
179→        win.maximize();
180→      }
181→    }
182→  });
183→
184→  ipcMain.handle("native:close", () => {
185→    const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
186→    win?.close();
187→  });
188→
189→  ipcMain.handle("native:isMaximized", () => {
190→    const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
191→    return win?.isMaximized() ?? false;
192→  });
193→
194→  ipcMain.handle("native:isFullscreen", () => {
195→    const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
196→    return win?.isFullScreen() ?? false;
197→  });
198→
199→  ipcMain.handle("native:toggleFullscreen", () => {
200→    const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
201→    if (win) {
202→      win.setFullScreen(!win.isFullScreen());
203→    }
204→  });
205→
206→  // Also register the snake_case aliases the preload named methods use
207→  ipcMain.handle("native:showMainWindow", () => {
208→    const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
