235→function HeaderOpenButton({ workspacePath }: { workspacePath: string }) {
236→  const [apps, setApps] = useState<InstalledApp[]>([]);
237→  const [open, setOpen] = useState(false);
238→  const [copied, setCopied] = useState(false);
239→  const closeTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
240→  const isHoveringRef = useRef(false);
241→
242→  useEffect(() => {
243→    native.apps
244→      .getInstalled()
245→      .then(setApps)
246→      .catch(() => {});
247→  }, []);
248→
249→  function handleOpenInApp(appId: string) {
250→    setOpen(false);
251→    track("open_in_app", { app_id: appId });
252→    native.apps.openIn(appId, workspacePath).catch(() => {});
253→  }
254→
255→  function handleCopyPath() {
256→    navigator.clipboard
257→      .writeText(workspacePath)
258→      .then(() => {
259→        setCopied(true);
260→        setTimeout(() => setCopied(false), 2000);
261→      })
262→      .catch(() => {});
263→    setOpen(false);
264→  }
265→
266→  function handleOpen() {
267→    if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
268→    isHoveringRef.current = true;
269→    setOpen(true);
270→  }
271→
272→  function handleClose() {
273→    isHoveringRef.current = false;
274→    closeTimeoutRef.current = setTimeout(() => {
275→      if (!isHoveringRef.current) setOpen(false);
276→    }, 50);
277→  }
278→
279→  useEffect(() => {
280→    return () => {
281→      if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
282→    };
283→  }, []);
284→
285→  const trigger = (
286→    <button
287→      type="button"
288→      className="text-text-subtle border-border-strong hover:bg-bg-muted flex h-7 items-center gap-1 rounded-lg border px-2 transition-colors duration-200"
289→      onPointerEnter={apps.length > 0 ? handleOpen : undefined}
290→      onPointerLeave={apps.length > 0 ? handleClose : undefined}
291→    >
292→      <ArrowUpRight className="h-[11px] w-[11px]" />
293→      <span className="text-sm font-medium">Open</span>
294→      <ChevronDown className="text-text-muted h-2 w-2" />
295→    </button>
296→  );
297→
298→  // No apps detected — hide the button entirely (web mode or no editors installed)
299→  if (apps.length === 0) {
300→    return null;
301→  }
302→
303→  const groups = groupAppsByCategory(apps);
304→
305→  return (
306→    <DropdownMenu open={open} onOpenChange={setOpen} modal={false}>
307→      <DropdownMenuTrigger asChild>{trigger}</DropdownMenuTrigger>
308→      <DropdownMenuContent
309→        align="start"
310→        sideOffset={4}
311→        className="min-w-[140px] shadow-sm"
312→        onPointerEnter={handleOpen}
