 1→/**
 2→ * App icon utilities — fallback and categorization for installed applications.
 3→ *
 4→ * Real app icons are extracted from macOS via mdfind in the Electron main process.
 5→ * The frontend renders <img src={app.icon}> when available. AppIcon below is the
 6→ * generic fallback for the rare case where extraction fails.
 7→ */
 8→
 9→import { cn } from "@/shared/lib/utils";
10→
11→/**
12→ * Generic fallback icon — renders app's first letter in a muted rounded square.
13→ * Used only when native macOS icon extraction fails (app.icon is null/undefined).
14→ */
15→export function AppIcon({ appId, className }: { appId: string; className?: string }) {
16→  const initial = appId.charAt(0).toUpperCase();
17→
18→  return (
19→    <div
20→      className={cn(
21→        "bg-muted text-muted-foreground text-2xs inline-flex items-center justify-center rounded-xs font-semibold",
22→        className
23→      )}
24→    >
25→      {initial}
26→    </div>
27→  );
28→}
29→
30→// ---------------------------------------------------------------------------
31→// App categorization — used to group items in dropdowns
32→// ---------------------------------------------------------------------------
33→
34→type AppCategory = "editor" | "terminal" | "system";
35→
36→const TERMINAL_IDS = new Set(["terminal", "iterm", "warp"]);
37→const SYSTEM_IDS = new Set(["finder"]);
38→
39→export function getAppCategory(appId: string): AppCategory {
40→  if (TERMINAL_IDS.has(appId)) return "terminal";
41→  if (SYSTEM_IDS.has(appId)) return "system";
42→  return "editor";
43→}
44→
45→/**
46→ * Groups a flat list of apps into ordered categories for display.
47→ * Returns: editors first, then terminals, then system utilities.
48→ */
49→export function groupAppsByCategory<T extends { id: string }>(
50→  apps: T[]
51→): { category: AppCategory; apps: T[] }[] {
52→  const editors: T[] = [];
53→  const terminals: T[] = [];
54→  const system: T[] = [];
55→
56→  for (const app of apps) {
57→    const cat = getAppCategory(app.id);
58→    if (cat === "editor") editors.push(app);
59→    else if (cat === "terminal") terminals.push(app);
60→    else system.push(app);
