/**
 * App icon utilities — bundled icons and categorization for installed applications.
 *
 * Icons are bundled as static PNGs in /public/app-icons/ (like Codex and OpenDevs do).
 * This provides instant loading, consistent quality, and no runtime extraction overhead.
 * The Electron backend only reports which apps are installed — icon resolution is frontend-side.
 */

import { cn } from "@/shared/lib/utils";

// ---------------------------------------------------------------------------
// Bundled icon map — static PNGs for all known apps (shipped with the app)
// ---------------------------------------------------------------------------

const BUNDLED_ICONS: Record<string, string> = {
  cursor: "/app-icons/cursor.png",
  vscode: "/app-icons/vscode.png",
  "vscode-insiders": "/app-icons/vscode-insiders.png",
  windsurf: "/app-icons/windsurf.png",
  zed: "/app-icons/zed.png",
  xcode: "/app-icons/xcode.png",
  fleet: "/app-icons/fleet.png",
  intellij: "/app-icons/intellij.png",
  webstorm: "/app-icons/webstorm.png",
  sublime: "/app-icons/sublime.png",
  terminal: "/app-icons/terminal.png",
  iterm: "/app-icons/iterm.png",
  warp: "/app-icons/warp.png",
  finder: "/app-icons/finder.png",
};

/** Resolve the icon URL for an app. Prefers bundled static icon, falls back to
 *  the backend-extracted icon (base64 data URL), or null if neither exists. */
export function getAppIconUrl(appId: string, backendIcon?: string): string | null {
  return BUNDLED_ICONS[appId] ?? backendIcon ?? null;
}

/**
 * Generic fallback icon — renders app's first letter in a muted rounded square.
 * Used only when no bundled icon exists and backend extraction also fails.
 */
export function AppIcon({ appId, className }: { appId: string; className?: string }) {
  const initial = appId.charAt(0).toUpperCase();

  return (
    <div
      className={cn(
        "bg-muted text-muted-foreground text-2xs inline-flex items-center justify-center rounded-xs font-semibold",
        className
      )}
    >
      {initial}
    </div>
  );
}

