// ---------------------------------------------------------------------------
// HeaderOpenButton — split button: quick open (last-used) + dropdown
// ---------------------------------------------------------------------------

function HeaderOpenButton({ workspacePath }: { workspacePath: string }) {
  const [apps, setApps] = useState<InstalledApp[]>([]);
  const [open, setOpen] = useState(false);
  const [copied, setCopied] = useState(false);
  const [lastAppId, setLastAppId] = useLastOpenInApp();
  const closeTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
  const isHoveringRef = useRef(false);

  useEffect(() => {
    native.apps
      .getInstalled()
      .then(setApps)
      .catch(() => {});
  }, []);

  const lastApp = lastAppId ? apps.find((a) => a.id === lastAppId) ?? null : null;

  function handleOpenInApp(appId: string) {
    setOpen(false);
    setLastAppId(appId);
    track("open_in_app", { app_id: appId });
    native.apps.openIn(appId, workspacePath).catch(() => {});
  }

  function handleQuickOpen() {
    if (lastApp) {
      handleOpenInApp(lastApp.id);
    } else {
      setOpen(true);
    }
  }

  function handleCopyPath() {
    navigator.clipboard
      .writeText(workspacePath)
      .then(() => {
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
      })
      .catch(() => {});
    setOpen(false);
  }

  function handleOpen() {
    if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
    isHoveringRef.current = true;
    setOpen(true);
  }

  function handleClose() {
    isHoveringRef.current = false;
    closeTimeoutRef.current = setTimeout(() => {
      if (!isHoveringRef.current) setOpen(false);
    }, 50);
  }

  useEffect(() => {
    return () => {
      if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
    };
  }, []);

  if (apps.length === 0) {
    return null;
  }

  const groups = groupAppsByCategory(apps);

  return (
    <DropdownMenu open={open} onOpenChange={setOpen} modal={false}>
      <div className="border-border-strong flex h-7 items-center rounded-lg border">
        {/* Left: quick-open action */}
        <Tooltip delayDuration={200}>
          <TooltipTrigger asChild>
            <button
              type="button"
              onClick={handleQuickOpen}
              className="text-text-subtle hover:bg-bg-muted flex h-full items-center gap-1.5 rounded-l-lg px-2 transition-colors duration-200"
            >
              {lastApp ? (
                (() => {
                  const iconUrl = getAppIconUrl(lastApp.id, lastApp.icon);
                  return iconUrl ? (
                    <img
                      src={iconUrl}
                      alt=""
                      className="h-4 w-4 flex-shrink-0 rounded-xs"
                      draggable={false}
                    />
                  ) : (
                    <ArrowUpRight className="h-[11px] w-[11px]" />
                  );
                })()
              ) : (
                <ArrowUpRight className="h-[11px] w-[11px]" />
              )}
              <span className="text-sm font-medium">Open</span>
            </button>
          </TooltipTrigger>
          <TooltipContent side="bottom">
            <p className="text-xs">
              {lastApp ? `Open in ${lastApp.name}` : "Open in\u2026"}
              <span className="text-text-muted ml-2">\u2318O</span>
            </p>
          </TooltipContent>
        </Tooltip>

        {/* Divider */}
        <div className="bg-border-strong h-4 w-px" />

        {/* Right: dropdown chevron */}
        <DropdownMenuTrigger asChild>
          <button
            type="button"
            className="text-text-muted hover:bg-bg-muted hover:text-text-subtle flex h-full items-center rounded-r-lg px-1.5 transition-colors duration-200"
            onPointerEnter={handleOpen}
            onPointerLeave={handleClose}
          >
            <ChevronDown className="h-2.5 w-2.5" />
          </button>
        </DropdownMenuTrigger>
      </div>

      <DropdownMenuContent
        align="end"
        sideOffset={4}
        className="min-w-[140px] shadow-sm"
        onPointerEnter={handleOpen}
        onPointerLeave={handleClose}
      >
        {groups.map((group, groupIdx) => (
          <div key={group.category}>
            {groupIdx > 0 && <DropdownMenuSeparator />}
            {group.apps.map((app) => (
              <DropdownMenuItem
                key={app.id}
                onClick={() => handleOpenInApp(app.id)}
                className="cursor-pointer gap-2 py-1 text-xs"
              >
                {app.icon ? (
                  <img
                    src={app.icon}
                    alt=""
                    className="h-5 w-5 flex-shrink-0 rounded-xs"
                    draggable={false}
                  />
                ) : (
                  <AppIcon appId={app.id} className="h-5 w-5 flex-shrink-0" />
                )}
                <span className={lastApp?.id === app.id ? "font-medium" : ""}>
                  {app.name}
                </span>
                {lastApp?.id === app.id && (
                  <Check className="text-text-muted ml-auto h-3 w-3" />
                )}
              </DropdownMenuItem>
            ))}
          </div>
        ))}
        <DropdownMenuSeparator />
        <DropdownMenuItem
          onClick={handleCopyPath}
          className="text-text-muted cursor-pointer gap-2 py-1 text-xs"
        >
          {copied ? (
            <Check className="h-3.5 w-3.5 flex-shrink-0" />
          ) : (
            <Copy className="h-3.5 w-3.5 flex-shrink-0" />
          )}
          {copied ? "Copied!" : "Copy path"}
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

