 48→function fileManagerCommandForPlatform(platform: NodeJS.Platform): string {
 49→  switch (platform) {
 50→    case "darwin":
 51→      return "open";
 52→    case "win32":
 53→      return "explorer";
 54→    default:
 55→      return "xdg-open";
