 67→function resolveWindowsPathExtensions(env: NodeJS.ProcessEnv): ReadonlyArray<string> {
 68→  const rawValue = env.PATHEXT;
 69→  const fallback = [".COM", ".EXE", ".BAT", ".CMD"];
 70→  if (!rawValue) return fallback;
 71→
 72→  const parsed = rawValue
 73→    .split(";")
