 84→): ReadonlyArray<string> {
 85→  if (platform !== "win32") return [command];
 86→  const extension = extname(command);
 87→  const normalizedExtension = extension.toUpperCase();
 88→
 89→  if (extension.length > 0 && windowsPathExtensions.includes(normalizedExtension)) {
 90→    const commandWithoutExtension = command.slice(0, -extension.length);
 91→    return Array.from(
 92→      new Set([
 93→        command,
 94→        `${commandWithoutExtension}${normalizedExtension}`,
 95→        `${commandWithoutExtension}${normalizedExtension.toLowerCase()}`,
 96→      ]),
 97→    );
 98→  }
 99→
100→  const candidates: string[] = [];
101→  for (const extension of windowsPathExtensions) {
102→    candidates.push(`${command}${extension}`);
103→    candidates.push(`${command}${extension.toLowerCase()}`);
104→  }
105→  return Array.from(new Set(candidates));
106→}
107→
108→function isExecutableFile(
109→  filePath: string,
110→  platform: NodeJS.Platform,
111→  windowsPathExtensions: ReadonlyArray<string>,
112→): boolean {
113→  try {
114→    const stat = statSync(filePath);
115→    if (!stat.isFile()) return false;
116→    if (platform === "win32") {
117→      const extension = extname(filePath);
118→      if (extension.length === 0) return false;
119→      return windowsPathExtensions.includes(extension.toUpperCase());
120→    }
121→    accessSync(filePath, constants.X_OK);
122→    return true;
123→  } catch {
124→    return false;
125→  }
126→}
127→
128→function resolvePathDelimiter(platform: NodeJS.Platform): string {
129→  return platform === "win32" ? ";" : ":";
130→}
131→
132→export function isCommandAvailable(
133→  command: string,
134→  options: CommandAvailabilityOptions = {},
135→): boolean {
136→  const platform = options.platform ?? process.platform;
137→  const env = options.env ?? process.env;
138→  const windowsPathExtensions = platform === "win32" ? resolveWindowsPathExtensions(env) : [];
139→  const commandCandidates = resolveCommandCandidates(command, platform, windowsPathExtensions);
140→
141→  if (command.includes("/") || command.includes("\\")) {
142→    return commandCandidates.some((candidate) =>
143→      isExecutableFile(candidate, platform, windowsPathExtensions),
144→    );
145→  }
146→
147→  const pathValue = resolvePathEnvironmentVariable(env);
148→  if (pathValue.length === 0) return false;
149→  const pathEntries = pathValue
150→    .split(resolvePathDelimiter(platform))
151→    .map((entry) => stripWrappingQuotes(entry.trim()))
152→    .filter((entry) => entry.length > 0);
153→
154→  for (const pathEntry of pathEntries) {
155→    for (const candidate of commandCandidates) {
156→      if (isExecutableFile(join(pathEntry, candidate), platform, windowsPathExtensions)) {
157→        return true;
158→      }
159→    }
160→  }
161→  return false;
162→}
163→
164→export function resolveAvailableEditors(
165→  platform: NodeJS.Platform = process.platform,
166→  env: NodeJS.ProcessEnv = process.env,
167→): ReadonlyArray<EditorId> {
168→  const available: EditorId[] = [];
169→
170→  for (const editor of EDITORS) {
171→    const command = editor.command ?? fileManagerCommandForPlatform(platform);
172→    if (isCommandAvailable(command, { platform, env })) {
173→      available.push(editor.id);
174→    }
175→  }
176→
177→  return available;
178→}
