180→/**
181→ * OpenShape - Service API for browser and editor launch actions.
182→ */
183→export interface OpenShape {
184→  /**
185→   * Open a URL target in the default browser.
186→   */
187→  readonly openBrowser: (target: string) => Effect.Effect<void, OpenError>;
188→
189→  /**
190→   * Open a workspace path in a selected editor integration.
191→   *
192→   * Launches the editor as a detached process so server startup is not blocked.
193→   */
194→  readonly openInEditor: (input: OpenInEditorInput) => Effect.Effect<void, OpenError>;
195→}
196→
197→/**
198→ * Open - Service tag for browser/editor launch operations.
199→ */
200→export class Open extends ServiceMap.Service<Open, OpenShape>()("t3/open") {}
201→
202→// ==============================
203→// Implementations
204→// ==============================
205→
206→export const resolveEditorLaunch = Effect.fnUntraced(function* (
207→  input: OpenInEditorInput,
208→  platform: NodeJS.Platform = process.platform,
209→): Effect.fn.Return<EditorLaunch, OpenError> {
210→  const editorDef = EDITORS.find((editor) => editor.id === input.editor);
211→  if (!editorDef) {
212→    return yield* new OpenError({ message: `Unknown editor: ${input.editor}` });
213→  }
214→
215→  if (editorDef.command) {
216→    return shouldUseGotoFlag(editorDef.id, input.cwd)
217→      ? { command: editorDef.command, args: ["--goto", input.cwd] }
218→      : { command: editorDef.command, args: [input.cwd] };
219→  }
220→
221→  if (editorDef.id !== "file-manager") {
222→    return yield* new OpenError({ message: `Unsupported editor: ${input.editor}` });
223→  }
224→
225→  return { command: fileManagerCommandForPlatform(platform), args: [input.cwd] };
226→});
227→
228→export const launchDetached = (launch: EditorLaunch) =>
229→  Effect.gen(function* () {
230→    if (!isCommandAvailable(launch.command)) {
231→      return yield* new OpenError({ message: `Editor command not found: ${launch.command}` });
232→    }
233→
234→    yield* Effect.callback<void, OpenError>((resume) => {
235→      let child;
236→      try {
237→        child = spawn(launch.command, [...launch.args], {
238→          detached: true,
239→          stdio: "ignore",
240→          shell: process.platform === "win32",
241→        });
242→      } catch (error) {
243→        return resume(
244→          Effect.fail(new OpenError({ message: "failed to spawn detached process", cause: error })),
245→        );
246→      }
247→
248→      const handleSpawn = () => {
249→        child.unref();
250→        resume(Effect.void);
251→      };
252→
253→      child.once("spawn", handleSpawn);
254→      child.once("error", (cause) =>
255→        resume(Effect.fail(new OpenError({ message: "failed to spawn detached process", cause }))),
256→      );
257→    });
258→  });
259→
260→const make = Effect.gen(function* () {
261→  const open = yield* Effect.tryPromise({
262→    try: () => import("open"),
263→    catch: (cause) => new OpenError({ message: "failed to load browser opener", cause }),
264→  });
265→
266→  return {
267→    openBrowser: (target) =>
268→      Effect.tryPromise({
269→        try: () => open.default(target),
270→        catch: (cause) => new OpenError({ message: "Browser auto-open failed", cause }),
271→      }),
272→    openInEditor: (input) => Effect.flatMap(resolveEditorLaunch(input), launchDetached),
273→  } satisfies OpenShape;
274→});
275→
276→export const OpenLive = Layer.effect(Open, make);
