 48→export const OpenInPicker = memo(function OpenInPicker({
 49→  keybindings,
 50→  availableEditors,
 51→  openInCwd,
 52→}: {
 53→  keybindings: ResolvedKeybindingsConfig;
 54→  availableEditors: ReadonlyArray<EditorId>;
 55→  openInCwd: string | null;
 56→}) {
 57→  const [preferredEditor, setPreferredEditor] = usePreferredEditor(availableEditors);
 58→  const options = useMemo(
 59→    () => resolveOptions(navigator.platform, availableEditors),
 60→    [availableEditors],
 61→  );
 62→  const primaryOption = options.find(({ value }) => value === preferredEditor) ?? null;
 63→
 64→  const openInEditor = useCallback(
 65→    (editorId: EditorId | null) => {
 66→      const api = readNativeApi();
 67→      if (!api || !openInCwd) return;
 68→      const editor = editorId ?? preferredEditor;
 69→      if (!editor) return;
 70→      void api.shell.openInEditor(openInCwd, editor);
 71→      setPreferredEditor(editor);
 72→    },
 73→    [preferredEditor, openInCwd, setPreferredEditor],
 74→  );
 75→
 76→  const openFavoriteEditorShortcutLabel = useMemo(
 77→    () => shortcutLabelForCommand(keybindings, "editor.openFavorite"),
