 85→      if (!api || !openInCwd) return;
 86→      if (!preferredEditor) return;
 87→
 88→      e.preventDefault();
 89→      void api.shell.openInEditor(openInCwd, preferredEditor);
 90→    };
 91→    window.addEventListener("keydown", handler);
 92→    return () => window.removeEventListener("keydown", handler);
 93→  }, [preferredEditor, keybindings, openInCwd]);
 94→
 95→  return (
