104→        <span className="sr-only @sm/header-actions:not-sr-only @sm/header-actions:ml-0.5">
105→          Open
106→        </span>
107→      </Button>
108→      <GroupSeparator className="hidden @sm/header-actions:block" />
109→      <Menu>
110→        <MenuTrigger render={<Button aria-label="Copy options" size="icon-xs" variant="outline" />}>
111→          <ChevronDownIcon aria-hidden="true" className="size-4" />
112→        </MenuTrigger>
113→        <MenuPopup align="end">
114→          {options.length === 0 && <MenuItem disabled>No installed editors found</MenuItem>}
115→          {options.map(({ label, Icon, value }) => (
116→            <MenuItem key={value} onClick={() => openInEditor(value)}>
117→              <Icon aria-hidden="true" className="text-muted-foreground" />
118→              {label}
119→              {value === preferredEditor && openFavoriteEditorShortcutLabel && (
120→                <MenuShortcut>{openFavoriteEditorShortcutLabel}</MenuShortcut>
121→              )}
122→            </MenuItem>
123→          ))}
124→        </MenuPopup>
125→      </Menu>
126→    </Group>
127→  );
128→});
