import { useState, useEffect, useRef } from "react";
import {
  ArrowUpRight,
  ChevronDown,
  PanelLeft,
  AlertTriangle,
  Loader2,
  RotateCw,
  ScrollText,
  Sparkles,
  Copy,
  Check,
} from "lucide-react";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { useSidebar } from "@/components/ui/sidebar";
import { cn } from "@/shared/lib/utils";
import { native } from "@/platform";
import type { InstalledApp } from "@/platform";
import { track } from "@/platform/analytics";
import type { SetupStatus } from "@/shared/types";
import type { WorkspaceStatus } from "@shared/enums";
import type { NormalizedTask } from "../api/workspace.service";
import { TaskStrip } from "./TaskStrip";
import { WorkflowStatusIcon } from "@/features/sidebar/ui/WorkflowStatusIcon";
import { WorkspaceStatusMenu } from "@/features/sidebar/ui/WorkspaceStatusMenu";
import { WORKFLOW_STATUS_CONFIG } from "@/features/sidebar/lib/status";
import { AppIcon, groupAppsByCategory } from "@/shared/lib/appIcons";
import { useLastOpenInApp } from "@/shared/hooks/useLastOpenInApp";
import { fixSetupErrorPrompt, GENERATE_HIVE_JSON } from "@/features/session/lib/sessionPrompts";

interface WorkspaceHeaderProps {
  title?: string;
  repositoryName?: string;
  branch?: string;
  workspacePath?: string;
  setupStatus?: SetupStatus;
  setupError?: string | null;
  onSendAgentMessage?: (text: string) => void;
  onRetrySetup?: () => void;
  onViewSetupLogs?: () => void;
  workspaceStatus?: WorkspaceStatus;
  onStatusChange?: (status: WorkspaceStatus) => void;
  tasks?: NormalizedTask[];
  hasManifest?: boolean;
  onRunTask?: (taskName: string) => void;
  /** Compact mode for mobile -- always show hamburger, hide Open button, tighter truncation */
  mobile?: boolean;
}

/**
 * Workspace title header — sits at the top of the LEFT (chat) panel.
 *
 * Simple 36px bar: title + repo/branch on left, Open button on right.
 * PR actions have moved to the right panel's ContentPanelHeader.
 */
export function WorkspaceHeader({
  title,
  repositoryName,
  branch,
  workspacePath,
  setupStatus,
  setupError,
  onSendAgentMessage,
  onRetrySetup,
  onViewSetupLogs,
  workspaceStatus,
  onStatusChange,
  tasks,
  hasManifest,
  onRunTask,
  mobile,
}: WorkspaceHeaderProps) {
  const { state: sidebarState, toggleSidebar } = useSidebar();
  const sidebarCollapsed = sidebarState === "collapsed";
  const showSidebarToggle = sidebarCollapsed || mobile;

  const subtitle = [repositoryName, branch].filter(Boolean).join(" / ");

  return (
    <div
      data-slot="workspace-header"
      className="drag-region flex h-11 flex-shrink-0 items-center justify-between px-4"
    >
      {/* Left: sidebar toggle + title + repo/branch */}
      <div className="flex min-w-0 items-center gap-[5px]">
        {showSidebarToggle && (
          <Tooltip delayDuration={200}>
            <TooltipTrigger asChild>
              <button
                type="button"
                aria-label="Expand sidebar"
                onClick={toggleSidebar}
                className="text-text-muted hover:text-text-secondary hover:bg-bg-muted mr-1 -ml-1 flex h-6 w-6 flex-shrink-0 items-center justify-center rounded-lg transition-colors duration-200"
              >
                <PanelLeft className="h-3.5 w-3.5" />
              </button>
            </TooltipTrigger>
            <TooltipContent side="bottom">
              <p className="text-xs">Open sidebar</p>
            </TooltipContent>
          </Tooltip>
        )}

        {workspaceStatus && onStatusChange && (
          <WorkspaceStatusMenu currentStatus={workspaceStatus} onStatusChange={onStatusChange}>
            <button
              type="button"
              className="text-text-muted hover:text-text-secondary mr-1 flex items-center gap-1 rounded-lg px-1 py-0.5 transition-colors duration-200"
            >
              <WorkflowStatusIcon status={workspaceStatus} size={14} />
            </button>
          </WorkspaceStatusMenu>
        )}

        {title && (
          <span
            className={cn(
              "text-foreground mr-0.5 truncate text-sm font-medium",
              mobile ? "max-w-[120px]" : "max-w-[240px]"
            )}
          >
            {title}
          </span>
        )}

        {subtitle && (
          <span
            className={cn(
              "truncate text-sm font-medium",
              mobile ? "max-w-[140px]" : "max-w-[280px]",
              title ? "text-text-subtle" : "text-foreground"
            )}
            title={subtitle}
          >
            {subtitle}
          </span>
        )}

        {setupStatus === "running" && (
          <span className="text-text-muted flex items-center gap-1 text-sm">
            <Loader2 className="h-3 w-3 animate-spin" />
            <span>Installing...</span>
          </span>
        )}
        {setupStatus === "failed" && (
          <div className="flex items-center gap-1">
            <span className="text-accent-red-muted flex items-center gap-1 text-sm font-medium">
              <AlertTriangle className="h-3 w-3" />
              <span>Setup failed</span>
            </span>
            {onViewSetupLogs && (
              <Tooltip delayDuration={200}>
                <TooltipTrigger asChild>
                  <button
                    type="button"
                    onClick={onViewSetupLogs}
                    className="text-text-muted hover:text-text-secondary rounded-lg px-1.5 py-0.5 text-xs transition-colors duration-200"
                  >
                    <ScrollText className="h-3 w-3" />
                  </button>
                </TooltipTrigger>
                <TooltipContent side="bottom">
                  <p className="text-xs">View setup logs</p>
                </TooltipContent>
              </Tooltip>
            )}
            {onSendAgentMessage && (
              <Tooltip delayDuration={200}>
                <TooltipTrigger asChild>
                  <button
                    type="button"
                    onClick={() => onSendAgentMessage(fixSetupErrorPrompt(setupError ?? null))}
                    className="text-text-muted hover:text-text-secondary rounded-lg px-1.5 py-0.5 text-xs transition-colors duration-200"
                  >
                    <Sparkles className="h-3 w-3" />
                  </button>
                </TooltipTrigger>
                <TooltipContent side="bottom">
                  <p className="text-xs">Ask AI to fix</p>
                </TooltipContent>
              </Tooltip>
            )}
            {onRetrySetup && (
              <Tooltip delayDuration={200}>
                <TooltipTrigger asChild>
                  <button
                    type="button"
                    onClick={onRetrySetup}
                    className="text-text-muted hover:text-text-secondary rounded-lg px-1.5 py-0.5 text-xs transition-colors duration-200"
                  >
                    <RotateCw className="h-3 w-3" />
                  </button>
                </TooltipTrigger>
                <TooltipContent side="bottom">
                  <p className="text-xs">Retry setup</p>
                </TooltipContent>
              </Tooltip>
            )}
          </div>
        )}

        {onRunTask && !mobile && (
          <TaskStrip
            tasks={tasks ?? []}
            hasManifest={hasManifest ?? false}
            disabled={setupStatus === "running"}
            onRunTask={onRunTask}
            onSetupEnvironment={
              onSendAgentMessage ? () => onSendAgentMessage(GENERATE_HIVE_JSON) : undefined
            }
          />
        )}
      </div>

      {/* Right: Open button (desktop only) */}
      {!mobile && (
        <div className="flex items-center">
          {workspacePath && <HeaderOpenButton workspacePath={workspacePath} />}
        </div>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// HeaderOpenButton — split button: quick open (last-used) + dropdown
// ---------------------------------------------------------------------------

function HeaderOpenButton({ workspacePath }: { workspacePath: string }) {
  const [apps, setApps] = useState<InstalledApp[]>([]);
  const [open, setOpen] = useState(false);
  const [copied, setCopied] = useState(false);
  const [lastAppId, setLastAppId] = useLastOpenInApp();
  const closeTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
  const isHoveringRef = useRef(false);

  useEffect(() => {
    native.apps
      .getInstalled()
      .then(setApps)
      .catch(() => {});
  }, []);

  const lastApp = lastAppId ? apps.find((a) => a.id === lastAppId) ?? null : null;

  function handleOpenInApp(appId: string) {
    setOpen(false);
    setLastAppId(appId);
    track("open_in_app", { app_id: appId });
    native.apps.openIn(appId, workspacePath).catch(() => {});
  }

  function handleQuickOpen() {
    if (lastApp) {
      handleOpenInApp(lastApp.id);
    } else {
      setOpen(true);
    }
  }

  function handleCopyPath() {
    navigator.clipboard
      .writeText(workspacePath)
      .then(() => {
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
      })
      .catch(() => {});
    setOpen(false);
  }

  function handleOpen() {
    if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
    isHoveringRef.current = true;
    setOpen(true);
  }

  function handleClose() {
    isHoveringRef.current = false;
    closeTimeoutRef.current = setTimeout(() => {
      if (!isHoveringRef.current) setOpen(false);
    }, 50);
  }

  useEffect(() => {
    return () => {
      if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
    };
  }, []);

  if (apps.length === 0) {
    return null;
  }

  const groups = groupAppsByCategory(apps);

  return (
    <DropdownMenu open={open} onOpenChange={setOpen} modal={false}>
      <div className="border-border-strong flex h-7 items-center rounded-lg border">
        {/* Left: quick-open action */}
        <Tooltip delayDuration={200}>
          <TooltipTrigger asChild>
            <button
              type="button"
              onClick={handleQuickOpen}
              className="text-text-subtle hover:bg-bg-muted flex h-full items-center gap-1.5 rounded-l-lg px-2 transition-colors duration-200"
            >
              {lastApp?.icon ? (
                <img
                  src={lastApp.icon}
                  alt=""
                  className="h-4 w-4 flex-shrink-0 rounded-xs"
                  draggable={false}
                />
              ) : (
                <ArrowUpRight className="h-[11px] w-[11px]" />
              )}
              <span className="text-sm font-medium">Open</span>
            </button>
          </TooltipTrigger>
          <TooltipContent side="bottom">
            <p className="text-xs">
              {lastApp ? `Open in ${lastApp.name}` : "Open in\u2026"}
              <span className="text-text-muted ml-2">\u2318O</span>
            </p>
          </TooltipContent>
        </Tooltip>

        {/* Divider */}
        <div className="bg-border-strong h-4 w-px" />

        {/* Right: dropdown chevron */}
        <DropdownMenuTrigger asChild>
          <button
            type="button"
            className="text-text-muted hover:bg-bg-muted hover:text-text-subtle flex h-full items-center rounded-r-lg px-1.5 transition-colors duration-200"
            onPointerEnter={handleOpen}
            onPointerLeave={handleClose}
          >
            <ChevronDown className="h-2.5 w-2.5" />
          </button>
        </DropdownMenuTrigger>
      </div>

      <DropdownMenuContent
        align="end"
        sideOffset={4}
        className="min-w-[140px] shadow-sm"
        onPointerEnter={handleOpen}
        onPointerLeave={handleClose}
      >
        {groups.map((group, groupIdx) => (
          <div key={group.category}>
            {groupIdx > 0 && <DropdownMenuSeparator />}
            {group.apps.map((app) => {
              const iconUrl = getAppIconUrl(app.id, app.icon);
              return (
                <DropdownMenuItem
                  key={app.id}
                  onClick={() => handleOpenInApp(app.id)}
                  className="cursor-pointer gap-2 py-1 text-xs"
                >
                  {iconUrl ? (
                    <img
                      src={iconUrl}
                      alt=""
                      className="h-5 w-5 flex-shrink-0 rounded-xs"
                      draggable={false}
                    />
                  ) : (
                    <AppIcon appId={app.id} className="h-5 w-5 flex-shrink-0" />
                  )}
                  <span className={lastApp?.id === app.id ? "font-medium" : ""}>
                    {app.name}
                  </span>
                  {lastApp?.id === app.id && (
                    <Check className="text-text-muted ml-auto h-3 w-3" />
                  )}
                </DropdownMenuItem>
              );
            })}
          </div>
        ))}
        <DropdownMenuSeparator />
        <DropdownMenuItem
          onClick={handleCopyPath}
          className="text-text-muted cursor-pointer gap-2 py-1 text-xs"
        >
          {copied ? (
            <Check className="h-3.5 w-3.5 flex-shrink-0" />
          ) : (
            <Copy className="h-3.5 w-3.5 flex-shrink-0" />
          )}
          {copied ? "Copied!" : "Copy path"}
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

import { useState, useEffect, useRef } from "react";
import { native } from "@/platform";
import type { InstalledApp } from "@/platform";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { ArrowUpRight, ChevronRight, Check } from "lucide-react";
import { AppIcon, groupAppsByCategory, getAppIconUrl } from "@/shared/lib/appIcons";
import { useLastOpenInApp } from "@/shared/hooks/useLastOpenInApp";
import { track } from "@/platform/analytics";

interface OpenInDropdownProps {
  workspacePath: string;
  iconOnly?: boolean;
}

export function OpenInDropdown({ workspacePath, iconOnly = false }: OpenInDropdownProps) {
  const [installedApps, setInstalledApps] = useState<InstalledApp[]>([]);
  const [loading, setLoading] = useState(true);
  const [open, setOpen] = useState(false);
  const [lastAppId, setLastAppId] = useLastOpenInApp();
  const closeTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
  const isHoveringRef = useRef(false);

  useEffect(() => {
    async function loadInstalledApps() {
      try {
        const apps = await native.apps.getInstalled();
        setInstalledApps(apps);
      } catch {
        // May fail if the IPC handler isn't registered
      } finally {
        setLoading(false);
      }
    }

    loadInstalledApps();
  }, []);

  useEffect(() => {
    return () => {
      if (closeTimeoutRef.current) {
        clearTimeout(closeTimeoutRef.current);
      }
    };
  }, []);

  const lastApp = lastAppId ? installedApps.find((a) => a.id === lastAppId) ?? null : null;
  const lastAppIcon = lastApp ? getAppIconUrl(lastApp.id, lastApp.icon) : null;

  function handleOpenInApp(appId: string) {
    setOpen(false);
    setLastAppId(appId);
    track("open_in_app", { app_id: appId });
    native.apps.openIn(appId, workspacePath).catch((error) => {
      console.error(`Failed to open in ${appId}:`, error);
    });
  }

  function handleQuickOpen() {
    if (lastApp) {
      handleOpenInApp(lastApp.id);
    } else {
      setOpen(true);
    }
  }

  function handleOpen() {
    if (closeTimeoutRef.current) {
      clearTimeout(closeTimeoutRef.current);
    }
    isHoveringRef.current = true;
    setOpen(true);
  }

  function handleClose() {
    isHoveringRef.current = false;
    // Very short delay to handle rapid mouse movements
    closeTimeoutRef.current = setTimeout(() => {
      if (!isHoveringRef.current) {
        setOpen(false);
      }
    }, 50);
  }

  if (loading || installedApps.length === 0) {
    return null;
  }

  const groups = groupAppsByCategory(installedApps);

  const menuContent = (
    <DropdownMenuContent
      align="end"
      sideOffset={2}
      className="min-w-[140px] shadow-sm"
      onPointerEnter={handleOpen}
      onPointerLeave={handleClose}
    >
      {groups.map((group, groupIdx) => (
        <div key={group.category}>
          {groupIdx > 0 && <DropdownMenuSeparator />}
          {group.apps.map((app) => {
            const iconUrl = getAppIconUrl(app.id, app.icon);
            return (
              <DropdownMenuItem
                key={app.id}
                onClick={() => handleOpenInApp(app.id)}
                className="cursor-pointer gap-2 py-1 text-xs"
              >
                {iconUrl ? (
                  <img
                    src={iconUrl}
                    alt=""
                    className="h-5 w-5 flex-shrink-0 rounded-xs"
                    draggable={false}
                  />
                ) : (
                  <AppIcon appId={app.id} className="h-5 w-5 flex-shrink-0" />
                )}
                <span className={lastApp?.id === app.id ? "font-medium" : ""}>
                  {app.name}
                </span>
                {lastApp?.id === app.id && (
                  <Check className="text-muted-foreground ml-auto h-3 w-3" />
                )}
              </DropdownMenuItem>
            );
          })}
        </div>
      ))}
    </DropdownMenuContent>
  );

  if (iconOnly) {
    return (
      <DropdownMenu open={open} onOpenChange={setOpen} modal={false}>
        <Tooltip delayDuration={200}>
          <DropdownMenuTrigger asChild>
            <TooltipTrigger asChild>
              <Button
                variant="ghost"
                size="icon"
                className="text-muted-foreground/80 hover:text-foreground hover:bg-muted/10 h-9 w-9 rounded-lg transition-colors duration-200 ease-out"
                onClick={(e) => {
                  if (lastApp) {
                    e.preventDefault();
                    handleOpenInApp(lastApp.id);
                  }
                }}
              >
                {lastAppIcon ? (
                  <img
                    src={lastAppIcon}
                    alt=""
                    className="h-4 w-4 rounded-xs"
                    draggable={false}
                  />
                ) : (
                  <ArrowUpRight className="h-4 w-4" />
                )}
              </Button>
            </TooltipTrigger>
          </DropdownMenuTrigger>
          <TooltipContent side="bottom">
            <p className="text-xs">
              {lastApp ? `Open in ${lastApp.name}` : "Open in\u2026"}
              <span className="text-muted-foreground ml-2">\u2318O</span>
            </p>
          </TooltipContent>
        </Tooltip>
        {menuContent}
      </DropdownMenu>
    );
  }

  return (
    <DropdownMenu open={open} onOpenChange={setOpen} modal={false}>
      <div className="border-border flex h-8 items-center rounded-lg border">
        <Tooltip delayDuration={200}>
          <TooltipTrigger asChild>
            <button
              type="button"
              onClick={handleQuickOpen}
              className="text-muted-foreground/80 hover:text-foreground hover:bg-muted/10 flex h-full items-center gap-2 rounded-l-lg px-3 transition-colors duration-200"
            >
              {lastApp?.icon ? (
                <img
                  src={lastApp.icon}
                  alt=""
                  className="h-4 w-4 rounded-xs"
                  draggable={false}
                />
              ) : (
